import './Box.scss';

import { classNames } from ':helpers/classnames';
import type { FC } from 'react';
import React from 'react';
import type { BoxProps } from './Box.types';

export const Box: FC<BoxProps> = ({
	as: Component = 'div',
	display = 'block',
	padding,
	paddingX,
	paddingY,
	margin,
	marginX,
	marginY,
	fullWidth,
	className,
	dataTestId = 'Box',
	...rest
}) => {
	const ComponentTag = Component as keyof React.JSX.IntrinsicElements;

	const boxClassName = classNames(
		'dsb_box',
		`dsb_box__display-${display}`,
		fullWidth && 'dsb_box__full-width',
		padding && `dsb_box__padding-${padding}`,
		paddingX && `dsb_box__padding-x-${paddingX}`,
		paddingY && `dsb_box__padding-y-${paddingY}`,
		margin && `dsb_box__margin-${margin}`,
		marginX && `dsb_box__margin-x-${marginX}`,
		marginY && `dsb_box__margin-y-${marginY}`,
		className,
	);

	return <ComponentTag data-testid={dataTestId} className={boxClassName} {...(rest as any)} />;
};

Box.displayName = 'Box';
